mapper.select:
SELECT * FROM device_credentials
WHERE device_id = #{deviceId}
  AND credential_key = #{credentialKey}
  AND active = TRUE
  AND (expires_at IS NULL OR expires_at > NOW())
LIMIT 1

mapper.update:
UPDATE device_credentials
SET active = #{active}, expires_at = #{expiresAt}
WHERE device_id = #{deviceId}
  AND credential_key = #{credentialKey}
